from __future__ import annotations
import hashlib
from dataclasses import dataclass
from typing import Optional

@dataclass
class DeduplicationResult:
    is_duplicate: bool
    existing_golden_id: Optional[str]
    match_method: Optional[str]   # "alias_match" or "content_hash_match" or None

class SourceDeduplicator:
    def __init__(self, catalog: "SourceCatalog") -> None:
        self._catalog = catalog

    def check(
        self,
        system: str,
        external_id: str,
        raw_text: str,
    ) -> DeduplicationResult:
        # 1. Alias match — same system + external_id already registered
        existing = self._catalog.find_by_alias(system, external_id)
        if existing:
            return DeduplicationResult(True, existing.golden_id, "alias_match")

        # 2. Content hash match — different alias, same bytes
        content_hash = hashlib.sha256(raw_text.encode()).hexdigest()
        existing = self._catalog.find_by_content_hash(content_hash)
        if existing:
            # Register new alias on the existing golden record
            existing.add_alias(system, external_id)
            self._catalog.save(existing)
            return DeduplicationResult(True, existing.golden_id, "content_hash_match")

        return DeduplicationResult(False, None, None)
